import anthropic

client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-3-5-sonnet-20241022",
    max_tokens=1024,
    tools=[
        {
            "type": "web_search_20250305",
            "name": "web_search",
        }
    ],
    messages=[
        {
            "role": "user",
            "content": "What is the current Python stable release version?"
        }
    ],
)

# The response may include tool_use blocks if Claude searched
for block in response.content:
    if block.type == "tool_use":
        print(f"Claude searched for: {block.input}")
    elif block.type == "text":
        print(block.text)
